#include <iostream>
#include <ctime>

void log_error(const char* message) {
    time_t rawtime;
    struct tm* timeinfo;

    time(&rawtime);
    timeinfo = localtime(&rawtime);

    char timestamp[20];
    strftime(timestamp, 20, "%Y-%m-%d %H:%M:%S", timeinfo);

    std::cout << timestamp << " ERROR: " << message << std::endl;
}